CREATE TABLE IF NOT EXISTS ${1:table_name} (
	${2:id} INT PRIMARY KEY AUTO_INCREMENT,
	${3:column_name} ${4:VARCHAR(255)}
)

CREATE VIEW ${1:view_name} AS
SELECT ${2:columns}
FROM ${3:table}
WHERE ${4:condition}

SELECT a.${1:column}, b.${2:column}
FROM ${3:table} a
INNER JOIN ${3:table} b ON a.${4:key} = b.${5:key}

CASE
	WHEN ${1:condition} THEN ${2:result}
	WHEN ${3:condition} THEN ${4:result}
	ELSE ${5:default}
END

WITH ${1:cte_name} AS (
	SELECT ${2:columns}
	FROM ${3:table}
	WHERE ${4:condition}
)
SELECT * FROM ${1:cte_name}

WITH RECURSIVE ${1:cte_name} AS (
	SELECT ${2:columns}
	FROM ${3:table}
	WHERE ${4:base_condition}
	UNION ALL
	SELECT ${5:columns}
	FROM ${3:table}
	INNER JOIN ${1:cte_name} ON ${6:join_condition}
)
SELECT * FROM ${1:cte_name}

CONSTRAINT ${1:fk_name} FOREIGN KEY (${2:column})
	REFERENCES ${3:parent_table}(${4:parent_column})
	ON DELETE ${5|CASCADE,SET NULL,RESTRICT,NO ACTION|}
	ON UPDATE ${6|CASCADE,SET NULL,RESTRICT,NO ACTION|}

SELECT ${1:columns}
FROM ${2:table} t1
WHERE ${3:column} ${4:operator} (
	SELECT ${5:aggregate}(${6:column})
	FROM ${2:table} t2
	WHERE t2.${7:key} = t1.${7:key}
)

CREATE TRIGGER ${1:trigger_name}
${2|BEFORE,AFTER|} ${3|INSERT,UPDATE,DELETE|} ON ${4:table}
FOR EACH ROW
BEGIN
	${5:-- SQL statements}
END
